using BusinessLayer.Dtos.Operations; using BusinessLayer.IService.Operations; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc;
namespace API.Controllers.Operations;
[ApiController][Route("api/admin/branch-workforce")][Authorize(Policy="AdminOnly")]
public class BranchWorkforceController:OperationsControllerBase { private readonly IBranchWorkforceService _service; public BranchWorkforceController(IBranchWorkforceService s)=>_service=s; [HttpGet] public async Task<ActionResult> Get([FromQuery] Guid userId) => userId == Guid.Empty ? BadRequest(new { detail = "userId is required." }) : Ok(await _service.GetMembershipsAsync(userId)); [HttpPost("staff")] public async Task<ActionResult> AddStaff(CreateBranchMembershipRequest r)=>FromResult(await _service.AddStaffAsync(r)); [HttpPost("managers")] public async Task<ActionResult> AddManager(CreateBranchMembershipRequest r)=>FromResult(await _service.AddManagerAsync(r)); [HttpPatch("staff/{membershipId:guid}/end")] public async Task<ActionResult> EndStaff(Guid membershipId, EndBranchMembershipRequest r)=>FromResult(await _service.EndStaffAsync(membershipId, r)); [HttpPatch("managers/{membershipId:guid}/deactivate")] public async Task<ActionResult> DeactivateManager(Guid membershipId)=>FromResult(await _service.DeactivateManagerAsync(membershipId)); }
